    return 1;
  }
  logger.info(`${succeeded} action(s) deployed`);
  return 0;
}

async function runRevert(
  options: CliOptions,
  manifest: Manifest,
  home: string,
): Promise<number> {
  const actions = options.agents
    ? planRevert(manifest, options.agents, home)
    : planRevertAll(manifest, home);
  if (actions.length === 0) {
    logger.info("No skills to revert.");
    return 0;
  }

  logger.info(
    `${dryRunPrefix(options.dryRun)}Reverting ${actions.length} action(s):`,
  );
  const { succeeded, skipped, failed, planned } = await executeRevert(
    actions,
    options.dryRun,
    options.verbose,
    home,
  );

  if (options.dryRun) {
    logger.info("");
    renderDryRunPlan(planned);
    logger.info("");
    logger.info(`${planned.length} action(s) would be removed (dry-run)`);
    return 0;
  }

  logger.info("");
  if (failed.length > 0) {
    const parts = [`${succeeded} removed`];
    if (skipped > 0) parts.push(`${skipped} skipped`);
    parts.push(`${failed.length} failed`);
    logger.info(parts.join(", "));
    return 1;
  }
  const parts = [`${succeeded} removed`];
  if (skipped > 0) parts.push(`${skipped} skipped`);
  logger.info(parts.join(", "));
  return 0;
}

const USER_ERROR_EXIT: Record<ErrorCode, number> = {
  INVALID_ARGS: 2,
  MANIFEST_INVALID: 3,
  DEPLOY_FAILED: 1,
  RESOLVE_FAILED: 1,
};

const debugMode = process.argv.includes("--debug");

try {
  process.exit(await main());
} catch (err) {
  if (err instanceof UserError) {
    logger.error(`Error: ${err.message}`);
    if (debugMode) {
      logger.errorRaw(err);
    }
    process.exit(USER_ERROR_EXIT[err.code]);
  } else {
    logger.error("Unexpected error. Run with --debug for details.");
    if (debugMode) {
      logger.errorRaw(err);
    }
    process.exit(1);
  }
}

